final:
module RefModule (
    input a,
    input b,
    input c,
    input d,
    input [1:0] sel,
    output y
);

    // 4-to-1 MUX logic
    wire __sel_tmp = (sel == 2'b00);
    assign y = __sel_tmp ? a : (sel == 2'b01) ? b :
               (sel == 2'b10) ? c :
                                d;

endmodule
